SELECT commongovernment13.agname AS agname,   commongovernment13.fundingagencyname AS fundingagencyname,   commongovernment13.level1category AS level1category,   CAST(EXTRACT(YEAR FROM (cast(commongovernment13.signeddate as DATE) + 3 * INTERVAL '1' MONTH)) AS BIGINT) AS yrsigneddateok FROM commongovernment13 GROUP BY commongovernment13.agname,   commongovernment13.fundingagencyname,   commongovernment13.level1category,   yrsigneddateok;
